"""PHAROS Repository Layer - CRUD operations."""

from datetime import datetime
from typing import Any

from .mongo import get_collection
from .schemas import (
    Ticket,
    TicketStatus,
    AgentType,
    AgentHistoryEntry,
    Decision,
)


class TicketRepository:
    """Repository for Ticket operations."""

    COLLECTION = "tickets"

    @classmethod
    def create(cls, ticket: Ticket) -> str:
        """Create a new ticket."""
        collection = get_collection(cls.COLLECTION)
        doc = ticket.model_dump(mode="json")
        collection.insert_one(doc)
        return ticket.ticket_id

    @classmethod
    def get(cls, ticket_id: str) -> Ticket | None:
        """Get a ticket by ID."""
        collection = get_collection(cls.COLLECTION)
        doc = collection.find_one({"ticket_id": ticket_id})
        if doc:
            doc.pop("_id", None)
            return Ticket.model_validate(doc)
        return None

    @classmethod
    def update(cls, ticket: Ticket) -> bool:
        """Update an existing ticket."""
        collection = get_collection(cls.COLLECTION)
        ticket.updated_at = datetime.utcnow()
        doc = ticket.model_dump(mode="json")
        result = collection.update_one(
            {"ticket_id": ticket.ticket_id},
            {"$set": doc}
        )
        return result.modified_count > 0

    @classmethod
    def list_by_status(cls, status: TicketStatus, limit: int = 50) -> list[Ticket]:
        """List tickets by status."""
        collection = get_collection(cls.COLLECTION)
        docs = collection.find({"status": status.value}).sort("created_at", -1).limit(limit)
        tickets = []
        for doc in docs:
            doc.pop("_id", None)
            tickets.append(Ticket.model_validate(doc))
        return tickets

    @classmethod
    def list_pending_review(cls) -> list[Ticket]:
        """List tickets pending any kind of review."""
        collection = get_collection(cls.COLLECTION)
        docs = collection.find({
            "status": {"$in": [
                TicketStatus.SPEC_PENDING.value,
                TicketStatus.REVIEW_PENDING.value,
            ]}
        }).sort("created_at", 1)
        tickets = []
        for doc in docs:
            doc.pop("_id", None)
            tickets.append(Ticket.model_validate(doc))
        return tickets

    @classmethod
    def get_next_ticket_id(cls) -> str:
        """Generate next ticket ID."""
        collection = get_collection(cls.COLLECTION)
        count = collection.count_documents({})
        year = datetime.utcnow().year
        return f"TKT-{year}-{count + 1:04d}"

    @classmethod
    def delete(cls, ticket_id: str) -> bool:
        """Delete a ticket."""
        collection = get_collection(cls.COLLECTION)
        result = collection.delete_one({"ticket_id": ticket_id})
        return result.deleted_count > 0


class AgentHistoryRepository:
    """Repository for agent execution history."""

    COLLECTION = "agent_history"

    @classmethod
    def create(cls, entry: AgentHistoryEntry) -> None:
        """Record an agent execution."""
        collection = get_collection(cls.COLLECTION)
        doc = entry.model_dump(mode="json")
        collection.insert_one(doc)

    @classmethod
    def get_by_ticket(cls, ticket_id: str, limit: int = 100) -> list[AgentHistoryEntry]:
        """Get history for a ticket."""
        collection = get_collection(cls.COLLECTION)
        docs = collection.find({"ticket_id": ticket_id}).sort("timestamp", -1).limit(limit)
        entries = []
        for doc in docs:
            doc.pop("_id", None)
            entries.append(AgentHistoryEntry.model_validate(doc))
        return entries

    @classmethod
    def get_by_agent(cls, agent: AgentType, limit: int = 100) -> list[AgentHistoryEntry]:
        """Get history for an agent."""
        collection = get_collection(cls.COLLECTION)
        docs = collection.find({"agent": agent.value}).sort("timestamp", -1).limit(limit)
        entries = []
        for doc in docs:
            doc.pop("_id", None)
            entries.append(AgentHistoryEntry.model_validate(doc))
        return entries


class DecisionRepository:
    """Repository for Architecture Decision Records."""

    COLLECTION = "decisions"

    @classmethod
    def create(cls, decision: Decision) -> str:
        """Create a new decision record."""
        collection = get_collection(cls.COLLECTION)
        doc = decision.model_dump(mode="json")
        collection.insert_one(doc)
        return decision.decision_id

    @classmethod
    def get(cls, decision_id: str) -> Decision | None:
        """Get a decision by ID."""
        collection = get_collection(cls.COLLECTION)
        doc = collection.find_one({"decision_id": decision_id})
        if doc:
            doc.pop("_id", None)
            return Decision.model_validate(doc)
        return None

    @classmethod
    def list_all(cls) -> list[Decision]:
        """List all decisions."""
        collection = get_collection(cls.COLLECTION)
        docs = collection.find({}).sort("created_at", -1)
        decisions = []
        for doc in docs:
            doc.pop("_id", None)
            decisions.append(Decision.model_validate(doc))
        return decisions

